parameters.jsCode:
/**
 * Parse WhatsApp Message — extrait le message du payload Meta
 */
const body = $input.first().json.body;

// Vérifier que c'est bien un message (pas un status update)
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;

if (!value?.messages || value.messages.length === 0) {
  // Status update (delivered, read, etc.) — ignorer
  return [{ json: { skip: true } }];
}

const message = value.messages[0];
const contact = value.contacts?.[0];
const metadata = value.metadata;

// Extraire le texte du message
let messageText = '';
if (message.type === 'text') {
  messageText = message.text?.body || '';
} else if (message.type === 'interactive') {
  messageText = message.interactive?.button_reply?.title || message.interactive?.list_reply?.title || '';
} else {
  messageText = '[Message non-texte: ' + message.type + ']';
}

return [{
  json: {
    skip: false,
    sender_phone: message.from,
    sender_name: contact?.profile?.name || 'Inconnu',
    message_text: messageText,
    message_id: message.id,
    timestamp: message.timestamp,
    phone_number_id: metadata?.phone_number_id,
    waba_id: entry?.id
  }
}];

/**
 * Build Booking Payload — prépare les données pour le workflow booking-conversation
 */
const msg = $('Parse WhatsApp Message').first().json;
const merchants = $('Find Merchant').first().json;
const clients = $('Find or Create Client').first().json;

const merchant = Array.isArray(merchants) ? merchants[0] : merchants;
const client = Array.isArray(clients) && clients.length > 0 ? clients[0] : null;

return [{
  json: {
    merchant_id: merchant?.id || '',
    channel: 'whatsapp',
    sender_id: msg.sender_phone,
    message_text: msg.message_text,
    client_name: client ? (client.first_name + ' ' + (client.last_name || '')).trim() : msg.sender_name,
    client_id: client?.id || null,
    salon_name: merchant?.name || 'Salon',
    ai_name: merchant?.ai_name || 'AurA',
    ai_tone: merchant?.ai_tone || 'friendly',
    preferred_language: (merchant?.ai_languages || ['fr'])[0] === 'fr' ? 'français' : 'english',
    preferred_service: 'aucun',
    preferred_practitioner: 'aucun',
    loyalty_points: client?.loyalty_points || 0,
    cancellation_delay_minutes: merchant?.cancellation_delay_minutes || 120,
    conversation_history: 'Première interaction',
    available_slots_text: 'Aucun créneau chargé',
    // WhatsApp metadata pour la réponse
    wa_phone_number_id: msg.phone_number_id,
    wa_sender_phone: msg.sender_phone,
    wa_message_id: msg.message_id
  }
}];

